// validateDockerImage checks if a Docker image exists and is accessible.
// When Docker is not installed or the daemon is not running, validation is
// silently skipped (returns nil) rather than producing warnings. Container image
// availability is a runtime concern; compile-time validation is best-effort only.
func validateDockerImage(image string, verbose bool) error {
	dockerValidationLog.Printf("Validating Docker image: %s", image)

	// Reject names starting with '-' to prevent argument injection
	if strings.HasPrefix(image, "-") {
		return fmt.Errorf("container image name '%s' is invalid: names must not start with '-'", image)
	}

	// Check if docker CLI is available on PATH.
	// If Docker is not installed, silently skip validation. Image availability
	// is a runtime concern; failing fast at runtime is sufficient.
	_, err := exec.LookPath("docker")
	if err != nil {
		dockerValidationLog.Print("Docker not installed, skipping image validation")
		return nil
	}

	// Check if Docker daemon is actually running (cached check with short timeout).
	// If the daemon is not running, silently skip validation rather than emitting
	// noisy warnings that are irrelevant for environments where Docker is unavailable.
	if !isDockerDaemonRunning() {
		dockerValidationLog.Print("Docker daemon not running, skipping image validation")
		return nil
	}

